// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	// STRY0100152 
	if(isLoading){
		timeDueMessages(newValue);
		return;
	}

	timeDueMessages();
	function timeDueMessages(newValue){

		// STRY0091294
		var isSuspenseDateRequired = g_scratchpad.isSuspenseDateRequired;
		g_form.setMandatory('u_duration_time_due',isSuspenseDateRequired == 'true'); // To make mandatory

		g_form.showFieldMsg('u_duration_time_due', getMessage('Setting the Due Time will set the time of day on the {0}').replace('{0}',g_scratchpad.suspense_date_label), 'info', false);

		// need to set the message even on load
		if (g_scratchpad.u_warning_projected_due_date_before_child == 'true'){
			g_form.showFieldMsg('u_duration_time_due', getMessage('The projected {0} of one (1) or more Subtasks exceeds the projected {1}  of this task').replace('{0}', g_scratchpad.suspense_date_label).replace('{1}',g_scratchpad.suspense_date_label),'warning', false);
		}
		if (g_scratchpad.u_warning_projected_due_date_after_parent == 'true'){
			g_form.showFieldMsg('u_duration_time_due', getMessage("This Subtask's projected {0}  exceeds the projected {1} of the Parent Task").replace('{0}', g_scratchpad.suspense_date_label).replace('{1}',g_scratchpad.suspense_date_label), 'warning', false);
		}	


	}
}
